export const hskWords: HskWord[] = rawWords.map((w, i) => ({ ...w, id: String(i) }))

export const hskWordsByLevel: Record<number, HskWord[]> = {}
for (const word of hskWords) {
  if (!hskWordsByLevel[word.level]) hskWordsByLevel[word.level] = []
  hskWordsByLevel[word.level].push(word)
}
